function buildMetaDescription(tool: ToolData, seed: ToolContentSeed) {
  return (
    seed.metaDescription ||
    `${tool.description} Use this free ${tool.title.toLowerCase()} to get practical guidance, examples, FAQs, and related resources on ToolHub India.`
  )
}

function buildFaqs(tool: ToolData, seed: ToolContentSeed): FaqItem[] {
  const lowerTitle = tool.title.toLowerCase()
  const browserAnswer =
    tool.category === 'PDF' || tool.category === 'Image' || tool.category === 'Text' || tool.category === 'Developer'
      ? `The ${lowerTitle} works best in a modern browser such as current Chrome, Edge, Firefox, or Safari where file handling and live updates are reliable.`
      : `The ${lowerTitle} works best in a modern browser such as current Chrome, Edge, Firefox, or Safari so the interface and calculations stay responsive.`
  const offlineAnswer =
    tool.category === 'PDF' || tool.category === 'Image'
      ? `Some processing can continue in the browser after the page loads, but you should not rely on full offline support unless you have already opened the tool and confirmed the workflow on your device.`
      : `The calculator or utility runs in the browser, but offline behavior can vary by device and session, so it is safer to treat internet access as recommended rather than optional.`
  const bestPracticeAnswer = seed.tips.slice(0, 2).join(' ')

  return [
    {
      question: `Is the ${lowerTitle} free to use?`,
      answer: `Yes. This ${lowerTitle} is available as a free browser-based tool, with no signup required for the standard workflow.`,
    },
    {
      question: `Does the ${lowerTitle} keep my data private?`,
      answer:
        tool.category === 'PDF' || tool.category === 'Image' || tool.category === 'Text' || tool.category === 'Developer'
          ? `The tool is designed for browser-first use, which helps keep routine processing on your device. You should still avoid using sensitive content on shared machines or with risky browser extensions enabled.`
          : `The tool is designed for quick browser-based use. For sensitive scenarios, it is still wise to avoid shared devices and double-check what data you choose to enter.`,
    },
    {
      question: `Can I use the ${lowerTitle} on mobile?`,
      answer: `Usually yes. The page is responsive, although larger files or longer text can feel easier to manage on a laptop or desktop.`,
    },
    {
      question: `Which browsers work best with the ${lowerTitle}?`,
      answer: browserAnswer,
    },
    {
      question: `Does the ${lowerTitle} work offline?`,
      answer: offlineAnswer,
    },
    {
      question: `Are there limits when using the ${lowerTitle}?`,
      answer:
        tool.category === 'PDF' || tool.category === 'Image'
          ? `Real limits usually come from your browser, device memory, and file sizes rather than a signup gate. If a large file struggles, try a smaller batch or a lighter source file.`
          : `Practical limits usually come from browser performance and the complexity of the input rather than from an account restriction. Keeping inputs realistic usually gives the smoothest experience.`,
    },
    {
      question: `What is the best way to get accurate results from the ${lowerTitle}?`,
      answer: bestPracticeAnswer,
    },
    ...seed.faqFocus,
  ]
}

export function getToolSeoContentByTitle(title: string) {
  const tool = tools.find((item) => item.title === title)
  if (!tool) return null
  return getToolSeoContentBySlug(tool.slug)
}

export function getToolSeoContentBySlug(slug: string): ToolSeoContent | null {
  const tool = tools.find((item) => item.slug === slug)
  const seed = toolSeeds[slug]
  if (!tool || !seed) return null

  const relatedPostSlugs = seed.relatedPostSlugs || categoryRelatedPosts[tool.category] || []
  const categoryFeatures = categoryFeatureLibrary[tool.category] || []
  const categoryBenefits = categoryBenefitLibrary[tool.category] || []

  return {
    slug: tool.slug,
    category: tool.category,
    title: tool.title,
    metaTitle: `${tool.title} Online`,
    metaDescription: buildMetaDescription(tool, seed),
    usageTime: seed.usageTime,
    primaryCta: seed.primaryCta,
    heroIntro: seed.heroIntro,
    overview: seed.overview,
    useCases: seed.useCases,
    audience: seed.audience,
    features: [...seed.customFeatures, ...categoryFeatures].slice(0, 6),
    howTo: seed.howTo,
    example: seed.example,
    benefits: [...seed.customBenefits, ...categoryBenefits].slice(0, 6),
    faqs: buildFaqs(tool, seed),
    tips: seed.tips,
    internalLinkSlugs: tools
      .filter((item) => item.category === tool.category && item.slug !== tool.slug)
      .slice(0, 6)
      .map((item) => item.slug),
    relatedPostSlugs,
    keywords: seed.keywords,
  }
}
